external_knowledge:
The term 'online feeds' refers to feeds with a status of 'Online' in the feeds table; 
Total listeners for a feed are determined by the number of user IDs associated with the feed in the feed_listeners table; 
'Aviation' is a specific genre of feed.

sql:
SELECT genre
FROM feeds
WHERE listeners = (SELECT MAX(listeners) FROM feeds);

SELECT feed_name, status, MAX(listeners) AS max_listeners
FROM feeds
GROUP BY status;

SELECT feed_id, feed_name, MAX(listeners) AS max_listeners
FROM feeds
GROUP BY feed_id, feed_name;

SELECT listeners
FROM feeds
WHERE feed_id = 1;

SELECT COUNT(listener_id) AS total_listeners
FROM feed_listeners
WHERE feed_id = 2;

SELECT feed_name
FROM feeds
WHERE listeners > 100;

SELECT SUM(listeners) AS total_listeners
FROM feeds
WHERE genre = (SELECT genre_name FROM feed_genres WHERE genre_id = (SELECT genre_id FROM feed_genre_map WHERE feed_id = 1));

SELECT feed_name
FROM feeds
ORDER BY feed_name ASC;

